const n=document.getElementById("hamburger"),t=document.getElementById("sidebar");n?.addEventListener("click",()=>t?.classList.toggle("is-open"));document.addEventListener("click",e=>{t?.classList.contains("is-open")&&!t.contains(e.target)&&e.target!==n&&t.classList.remove("is-open")});document.addEventListener("keydown",e=>{(e.metaKey||e.ctrlKey)&&e.key==="k"&&(e.preventDefault(),document.getElementById("main-search")?.focus())});
